python -c "
import tiktoken
enc = tiktoken.get_encoding('gpt2')

def max_len_validator(tokens):
    if len(tokens) > 3:
        raise ValueError('too long')

try:
    enc.encode('hello world this is definitely too long', validators=[max_len_validator])
    print('no error - unexpected')
except ValueError as e:
    print('validator raised as expected:', e)

# chunk_size + validators together
def no_specific_token(tokens):
    if 995 in tokens:
        raise ValueError('contains disallowed token')

try:
    enc.encode('hello world ' * 50, chunk_size=20, validators=[no_specific_token])
    print('no error - unexpected')
except ValueError as e:
    print('chunk validator raised as expected:', e)
"
